param()
Set-Location "c:\ASK\MyWorkspace\sk-keys"
$d = "c:\ASK\MyWorkspace\sk-keys\dictionary\tier-5-distributed-architecture\SYD-system-design"

$gem   = [char]::ConvertFromUtf32(0x1F48E)
$bulb  = [char]::ConvertFromUtf32(0x1F4A1)
$brain = [char]::ConvertFromUtf32(0x1F9E0)
$link  = [char]::ConvertFromUtf32(0x1F517)
$star  = [char]0x2605
$empty = [char]0x2606

function Join-Lines { param([string[]]$lines) return $lines -join "`r`n" }

function Upgrade-SYD {
    param(
        [string]$filename,
        [string]$newYaml,
        [string]$inventionMomentQuote,
        [string]$evolutionText,
        [string]$newRelatedContent,
        [string]$twContent,
        [string]$stContent,
        [string]$newThinkContent
    )
    $fp = "$d\$filename"
    $c = [System.IO.File]::ReadAllText($fp, [System.Text.Encoding]::UTF8)
    $nl = if ($c.Contains("`r`n")) { "`r`n" } else { "`n" }
    $fmEnd = $c.IndexOf("---", 4)
    $afterFm = $c.Substring($fmEnd + 3)
    $c = $newYaml + $afterFm
    if ($c.Contains($inventionMomentQuote)) {
        $c = $c.Replace($inventionMomentQuote, $inventionMomentQuote + $nl + $nl + "**EVOLUTION:**" + $nl + $evolutionText)
    } else { Write-Warning "Invention moment not found in $filename" }
    $rkHeader = "### $link Related Keywords"
    $rkPos = $c.IndexOf($rkHeader)
    if ($rkPos -ge 0) {
        $afterRk = $c.IndexOf("---", $rkPos + $rkHeader.Length)
        $c = $c.Substring(0, $rkPos) + $rkHeader + $nl + $nl + $newRelatedContent + $nl + $nl + $c.Substring($afterRk)
    } else { Write-Warning "Related Keywords not found in $filename" }
    $thinkHeader = "### $brain Think About This Before We Continue"
    $thinkPos = $c.IndexOf($thinkHeader)
    if ($thinkPos -ge 0) {
        $dashBefore = $c.LastIndexOf($nl + "---" + $nl, $thinkPos)
        $bodyPart = $c.Substring(0, $dashBefore)
        $c = $bodyPart + $nl + "---" + $nl + $nl +
            "### $gem Transferable Wisdom" + $nl + $nl + $twContent + $nl + $nl +
            "---" + $nl + $nl +
            "### $bulb The Surprising Truth" + $nl + $nl + $stContent + $nl + $nl +
            "---" + $nl + $nl +
            $thinkHeader + $nl + $nl + $newThinkContent + $nl
    } else { Write-Warning "Think section not found in $filename" }
    $c = $c.Replace("_Hint:_", "*Hint:*")
    [System.IO.File]::WriteAllText($fp, $c, [System.Text.Encoding]::UTF8)
    Write-Host "OK: $filename" -ForegroundColor Green
}

# ============================================================
# SYD-016 - Error Budget
# ============================================================
$yaml016 = Join-Lines @("---","id: SYD-016","title: Error Budget","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-015","used_by:","related: SYD-015, SYD-017","tags:","  - reliability","  - advanced","  - observability","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 16","permalink: /syd/error-budget/","---")
$inv016 = '"What if we calculated how much failure we''re allowed, and used that to decide when to deploy? More budget = deploy more. Low budget = hold off."'
$evo016 = "Error budgets were formalised in Google's SRE book (2016), though the concept existed implicitly in how Google's SRE teams balanced reliability work against feature development. The framework spread rapidly: organisations adopted error budget policies as the mechanism for making deployment decisions data-driven rather than politics-driven. Modern implementations extend error budgets to burn rate alerts (Prometheus + SLO alerting), automated deployment freezes when budget drops below threshold, and multi-window consumption tracking (fast burn + slow burn). The discipline evolved from a Google-specific practice into an industry-standard reliability engineering tool."
$rk016 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-015 - SLA SLO SLI]] - error budget is derived from SLO","","**Builds On This (learn these next):**","- [[SYD-017 - MTTR MTBF]] - incident recovery time affects error budget burn rate","","**Alternatives / Comparisons:**","- [[SYD-017 - MTTR MTBF]] - MTTR/MTBF determine the burn rate from incidents","- [[SYD-015 - SLA SLO SLI]] - error budget is derived from these and feeds back into them")
$tw016 = Join-Lines @("**Reusable Engineering Principle:**","Permission to fail, budgeted in advance, enables risk-taking within safe boundaries. This principle appears everywhere: companies allocate R&D budgets for risky innovation (if all projects succeed, you're not taking enough risk), test suites have flakiness budgets (some flakiness is acceptable; zero is too expensive), and teams have on-call burden budgets (some on-call is unavoidable; too much causes burnout). Budget the acceptable failure; measure against it; make decisions within the budget.","","**Where else this pattern appears:**","- **R&D investment:** A product team's 20% innovation budget is an error budget for risky ideas - permission to fail on one in five experiments without consequence.","- **Test flakiness limits:** A CI pipeline that allows up to 2% test flakiness has an error budget for non-deterministic tests - beyond 2%, the suite is deemed unreliable.","- **On-call burden caps:** SRE teams cap on-call work at 50% of time - an error budget for operational toil that protects engineering capacity.")
$st016 = "Error budgets make the counterintuitive argument that you should spend your error budget as completely as possible. A team that ends the month with 90% of their error budget unused has been too conservative - they delayed features, avoided risks, and over-invested in reliability beyond what customers required. The SRE model explicitly frames full error budget consumption as the correct outcome: you have maximised feature delivery within your customer-committed reliability target. Leftover error budget is waste - an opportunity cost paid in slower delivery."
$think016 = Join-Lines @("**Q1.** Your service SLA = 99.9% (monthly). You have 10 features ready to ship, but error budget is nearly exhausted (< 5% remaining). One feature is high-risk (5% chance of 1-hour outage). Another is low-risk (0.1% chance of 10-minute outage). Which do you deploy, and why?","","*Hint:* Think about what deploying each feature means for error budget in the worst case - calculate the expected burn for each (probability x outage duration as % of monthly budget). Explore whether deploying both sequentially rather than simultaneously changes the risk calculation.","","**Q2.** You notice your burn rate is 1.5x the safe rate. Actual incidents (infrastructure failures) caused 60% of the burn, and deployments caused 40%. Should you freeze all deployments, or focus on preventing incidents? What's the tradeoff?","","*Hint:* Think about the source of burns - infrastructure failures vs deployments - and whether freezing deployments addresses the 60% that is not deployment-caused. Explore whether the burn rate difference (1.5x) tells you which intervention has higher leverage.","","**Q3 (Root Cause):** Your error budget burns 3x faster in the first week of each month. You identify that batch jobs on the 1st cause database contention, which causes latency SLI violations. How would you address this without eliminating the batch jobs?","","*Hint:* Think about whether the SLI measures availability (binary) or latency (percentile-based). Explore whether scheduling batch jobs during low-traffic periods, or using read replicas to isolate batch query impact, reduces SLI violations without eliminating the batch work.")
Upgrade-SYD "SYD-016 - Error Budget.md" $yaml016 $inv016 $evo016 $rk016 $tw016 $st016 $think016

# ============================================================
# SYD-017 - MTTR MTBF
# ============================================================
$yaml017 = Join-Lines @("---","id: SYD-017","title: MTTR MTBF","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$empty","depends_on: SYD-015","used_by:","related: SYD-015, SYD-016, SYD-022","tags:","  - reliability","  - intermediate","  - observability","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 17","permalink: /syd/mttr-mtbf/","---")
$inv017 = '"What if we measured: How often do systems break (MTBF)? How fast do we fix them (MTTR)? Then reliability = less frequent breaks + faster fixes."'
$evo017 = "MTBF originated in military aviation in the 1940s - the US Army Air Forces tracked aircraft failure rates to predict maintenance intervals. MTTR emerged as its complement: once MTBF was known, reducing MTTR became the other lever for improving availability. Both metrics were adopted by telecommunications in the 1960s-70s, then by IT infrastructure in the 1990s. Modern SRE practice extends the concepts to mean time to detect (MTTD), mean time to acknowledge (MTTA), and mean time to resolve (MTTR) - breaking incident response into measurable phases. The discipline evolved from hardware reliability engineering to software service reliability management."
$rk017 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-015 - SLA SLO SLI]] - MTBF/MTTR determine achievable SLA","","**Builds On This (learn these next):**","- [[SYD-022 - Disaster Recovery]] - DR planning requires knowing MTTR for major failures","","**Alternatives / Comparisons:**","- [[SYD-018 - RTO RPO]] - similar metrics for disaster recovery scenarios","- [[SYD-016 - Error Budget]] - error budget burn rate is related to MTBF frequency")
$tw017 = Join-Lines @("**Reusable Engineering Principle:**","Decompose a complex outcome into its contributing factors to identify where to invest. Availability = MTBF / (MTBF + MTTR). You can improve availability by reducing either factor. This decomposition principle applies everywhere: delivery time = queue time + processing time (Little's Law), customer satisfaction = product quality x support quality x price, code review cycle time = time-to-review + time-to-address-feedback. Decompose first, then invest in the factor with highest leverage.","","**Where else this pattern appears:**","- **Incident response phases:** Breaking MTTR into MTTD + MTTA + TTR reveals which phase is the bottleneck - often detection takes longer than the actual fix.","- **Deployment pipeline:** Total deploy time = build time + test time + deploy time + validation time - each phase can be optimised independently.","- **Customer support:** Resolution time = queue time + diagnosis time + fix time + verification - decomposing reveals where to invest in automation.")
$tw017 = $tw017.Replace("x support", "* support")
$st017 = "Reducing MTTR below a certain threshold is more effective than eliminating failures entirely. A system with MTBF = 100 hours and MTTR = 1 minute achieves 99.998% availability. The marginal cost of eliminating the last 0.01% of failures grows exponentially (chaos engineering, full Byzantine fault tolerance), while reducing MTTR from 30 minutes to 3 minutes is often a process and tooling problem - achievable at low cost with better alerting, runbooks, and deployment automation. This is why Google's SRE teams invest more in detection and response tooling than in preventing every failure."
$think017 = Join-Lines @("**Q1.** Your API has SLA = 99% (7.2 hours downtime/month allowed). Current MTBF = 200 hours, MTTR = 30 minutes. Calculate availability. Are you meeting SLA? What needs to improve: MTBF or MTTR?","","*Hint:* Think about the formula: Availability = MTBF / (MTBF + MTTR). Calculate current availability and identify whether MTBF improvement or MTTR improvement yields a larger gain per dollar invested.","","**Q2.** You have a choice: invest $10K to reduce MTBF to 300 hours (prevent failures better) OR invest $10K to reduce MTTR to 10 minutes (recover faster). Which investment yields higher availability gain, and why?","","*Hint:* Think about the math: which investment makes a bigger change to the MTBF/(MTBF+MTTR) formula? Explore the diminishing returns of MTBF improvement when MTBF is already high compared to MTTR reduction when MTTR is the dominant term.","","**Q3 (Scale):** Your service handles 10,000 req/sec. An incident takes 45 minutes to resolve and occurs once per month. Post-mortem: detection took 15 min, triage took 15 min, fix took 15 min. Which phase should you invest in reducing, and how does it affect your SLA?","","*Hint:* Think about which phase is most amenable to technical improvement (monitoring alert speed vs debugging tooling vs deployment speed) versus process improvement (runbooks, escalation paths). Explore which 15-minute phase would have the largest availability impact if halved.")
Upgrade-SYD "SYD-017 - MTTR MTBF.md" $yaml017 $inv017 $evo017 $rk017 $tw017 $st017 $think017

# ============================================================
# SYD-018 - RTO RPO
# ============================================================
$yaml018 = Join-Lines @("---","id: SYD-018","title: RTO RPO","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-022","used_by:","related: SYD-022, SYD-023, SYD-017","tags:","  - reliability","  - advanced","  - distributed","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 18","permalink: /syd/rto-rpo/","---")
$inv018 = '"We need commitments: if disaster strikes, how fast must we recover? How much data loss is acceptable? Then we design systems to meet those targets."'
$evo018 = "RTO and RPO as formal concepts emerged from business continuity planning in the 1980s, formalised by British Standards Institute (BS 25999) and later ISO 22301. Initially applied to physical disaster recovery (offsite tape backups, alternate data centres), the concepts were adapted to software systems as cloud computing made multi-region deployment accessible. Modern cloud services expose RTO/RPO as configuration parameters: managed databases offer RPO in seconds (synchronous replication) or minutes (asynchronous replication), and cloud providers publish their own RTO/RPO commitments in SLAs. The discipline evolved from physical disaster planning to architectural design constraints."
$rk018 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-022 - Disaster Recovery]] - overall strategy; RTO/RPO are the metrics that define DR targets","","**Builds On This (learn these next):**","- [[SYD-023 - Geo-Replication]] - geographic distribution to achieve low RTO/RPO","","**Alternatives / Comparisons:**","- [[SYD-017 - MTTR MTBF]] - different but complementary (MTTR is reactive, RTO is proactive)","- [[SYD-016 - Error Budget]] - error budget includes planned DR test downtime")
$tw018 = Join-Lines @("**Reusable Engineering Principle:**","Define the acceptable loss before the disaster, not during it. Under pressure, without predefined constraints, teams make suboptimal decisions. This principle appears everywhere: circuit breaker thresholds (define trip conditions in advance), feature flags (define rollback criteria before shipping), incident severity levels (define P1/P2 criteria before incidents happen). Predefined targets create calm, rational decision-making during crises.","","**Where else this pattern appears:**","- **Circuit breakers:** Trip thresholds (error rate > 50%, latency > 2s) are RTO/RPO analogues - predefined bounds for acceptable failure before switching to fallback.","- **Kubernetes pod disruption budgets:** A PDB defines the minimum number of available pods during node maintenance - an RPO for pod availability.","- **Database backup policies:** Backup frequency determines RPO; recovery time testing determines RTO. Most teams discover their true RTO only when testing.")
$st018 = "RTO and RPO are inverse to cost: a 5-minute RTO with zero RPO (no data loss) requires real-time synchronous replication to a hot standby - this can cost 3-5x a single-region deployment. A 24-hour RTO with 24-hour RPO requires only daily backups to cold storage - this can cost 1/100th as much. Most businesses underestimate this cost curve and discover only when building DR systems that their 'we need to recover in under an hour' requirement implies architectural changes costing millions of dollars per year in replication infrastructure."
$think018 = Join-Lines @("**Q1.** Your payment system has: primary in us-east-1, backup in us-west-2. Network latency 50ms. RTO target: 10 minutes. Can you achieve it with warm standby + restore-from-backup strategy, or do you need hot standby (continuous replication)?","","*Hint:* Think about what warm standby means for startup time when the primary fails - how long does it take to initialise, load data, and start accepting traffic? Explore the difference between warm standby (pre-initialised but not running) and hot standby (continuously running, near-instant failover).","","**Q2.** You can invest in either: (A) reducing MTTR (faster incident response to normal outages) or (B) improving RTO/RPO (faster disaster recovery). Which is higher priority for a financial services company, and why?","","*Hint:* Think about the regulatory requirements of financial services - what does 24-hour data loss mean for a payment processor? Explore whether MTTR (faster recovery from normal outages) or RTO/RPO (data loss prevention in disasters) is the higher-severity risk for a regulated financial institution.","","**Q3 (Design Trade-off):** You're designing DR for a global e-commerce platform. The product catalog (read-heavy, slowly changing) has RTO = 5 min, RPO = 24 hours. The order database (write-heavy, every order must be recorded) has RTO = 5 min, RPO = 0. Design an architecture that meets both without over-engineering the catalog.","","*Hint:* Think about whether different data types warrant different DR strategies - a CDN-cached catalog can tolerate data loss because it can be rebuilt from source, while orders cannot be recreated. Explore how you implement RPO = 0 for orders (synchronous replication) while accepting RPO = 24h for the catalog (daily backups or async replication).")
Upgrade-SYD "SYD-018 - RTO RPO.md" $yaml018 $inv018 $evo018 $rk018 $tw018 $st018 $think018

# ============================================================
# SYD-019 - Redundancy Failover
# ============================================================
$yaml019 = Join-Lines @("---","id: SYD-019","title: Redundancy Failover","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$empty","depends_on: SYD-008","used_by: SYD-020, SYD-021","related: SYD-020, SYD-021, SYD-022","tags:","  - reliability","  - intermediate","  - architecture","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 19","permalink: /syd/redundancy-failover/","---")
$inv019 = '"Have a backup ready. If primary fails, automatically switch to backup. Instant recovery, no manual intervention."'
$evo019 = "Redundancy as an engineering principle predates computing - aerospace engineers duplicated flight-critical systems in the 1940s (dual engines, dual hydraulic systems). Computing adopted redundancy first for hardware (RAID for disk, dual power supplies for servers), then for software services (multiple application instances, database replicas). Cloud computing made redundancy cheap: deploying to two availability zones costs marginally more than one. Modern systems add application-level redundancy (circuit breakers, bulkheads) on top of infrastructure redundancy. The discipline evolved from hardware fault tolerance into a layered software architecture pattern."
$rk019 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-008 - Load Balancing]] - distributes traffic away from failed nodes","","**Builds On This (learn these next):**","- [[SYD-020 - Active-Active]] - both nodes serve traffic simultaneously","- [[SYD-021 - Active-Passive]] - one node waits as standby","- [[SYD-022 - Disaster Recovery]] - larger-scale failover across regions","","**Alternatives / Comparisons:**","- [[SYD-020 - Active-Active]] - both nodes active vs one passive","- [[SYD-021 - Active-Passive]] - simpler; one node waits as standby")
$tw019 = Join-Lines @("**Reusable Engineering Principle:**","Single points of failure are the enemy of availability. Any component in the critical path that has no redundant alternative becomes the limiting factor for system availability. This applies to supply chains (single-supplier risk), software architecture (single database primary, single message broker), and team structure (single person who knows a critical system). Identify the critical path, find the single points, and eliminate them systematically.","","**Where else this pattern appears:**","- **Network paths:** Enterprise networks use redundant switches, routers, and ISP uplinks - the same principle at the network layer.","- **Power supply:** Servers in data centres have dual power supplies connecting to separate PDUs on separate circuits - physical redundancy.","- **Code paths:** Feature flags with fallback logic are code-level redundancy - if the primary code path fails, fall back to the simpler version.")
$st019 = "Redundancy can create false confidence. A system with two servers and automatic failover is not 2x more available than a single server - it is only more available if the failure modes of the two servers are truly independent. A software bug that crashes Server 1 will crash Server 2 identically (correlated failure). A misconfigured network switch that isolates both servers simultaneously eliminates both (common-mode failure). Real redundancy requires fault isolation: different hardware, different availability zones, different software versions. Engineers who count replicas and assume independence often discover correlated failures the hard way."
$think019 = Join-Lines @("**Q1.** Your system has 3 redundant web servers with automatic failover. If one fails, the remaining 2 can't handle 100% of traffic (latency increases 50%). Is this acceptable design? Why or why not?","","*Hint:* Think about what happens to latency when 2 servers absorb 100% of traffic intended for 3 - is a 50% latency increase acceptable, and does that depend on your current baseline latency and SLA? Explore whether over-provisioning (sizing for N+1) is the correct design choice.","","**Q2.** During a failover event, your database replica is promoted to primary, but the old primary (now down) is still listed in DNS. Apps start connecting to both. How would you prevent split-brain scenarios?","","*Hint:* Think about what split-brain means: both servers think they are the primary and accept writes. Explore STONITH (Shoot The Other Node In The Head), distributed consensus (Raft/Paxos), and database-level mechanisms that prevent dual-primary scenarios.","","**Q3 (First Principles):** You have primary and standby databases with automatic failover. During testing, failover takes 30 seconds. Your application has connection retry logic with 5-second timeout - during those 30 seconds, 6 retry attempts fail. Design an application-level strategy that survives a 30-second failover transparently.","","*Hint:* Think about what retry logic looks like at the application level - exponential backoff with jitter spreads the retry load. Explore whether the database driver's connection failover (JDBC failover URL) operates independently of application-level retry, and whether circuit breakers can hold requests rather than failing them during the failover window.")
Upgrade-SYD "SYD-019 - Redundancy Failover.md" $yaml019 $inv019 $evo019 $rk019 $tw019 $st019 $think019

# ============================================================
# SYD-020 - Active-Active
# ============================================================
$yaml020 = Join-Lines @("---","id: SYD-020","title: Active-Active","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-008, SYD-019","used_by:","related: SYD-021, SYD-008, SYD-023","tags:","  - distributed","  - advanced","  - architecture","  - reliability","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 20","permalink: /syd/active-active/","---")
$inv020 = '"Both systems active, both serving traffic. If one fails, the other keeps going. No switchover needed, no downtime."'
$evo020 = "Active-Active architectures emerged from telecommunications in the 1990s, where carriers required no-downtime switching. Web-scale companies (Google, Amazon) applied active-active to global deployments in the 2000s to achieve both low latency (serve from nearest region) and high availability (survive regional failure). The engineering challenge shifted from software design to data synchronisation: making writes consistent across active nodes without a single master became the central problem. CRDTs, eventual consistency models, and distributed consensus algorithms (Paxos, Raft) evolved specifically to enable active-active data stores. The discipline evolved from HA infrastructure into distributed data architecture."
$rk020 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-019 - Redundancy Failover]] - the broader pattern that active-active implements","- [[SYD-008 - Load Balancing]] - distributes traffic across both active nodes","","**Builds On This (learn these next):**","- [[SYD-023 - Geo-Replication]] - data synchronisation strategy for active-active regions","- [[SYD-024 - Multi-Region Architecture]] - full multi-region design using active-active","","**Alternatives / Comparisons:**","- [[SYD-021 - Active-Passive]] - simpler; one node waits as standby, no conflict resolution","- [[SYD-019 - Redundancy Failover]] - broader pattern; active-active is one implementation")
$tw020 = Join-Lines @("**Reusable Engineering Principle:**","Make all nodes first-class citizens; none of them special. This principle - eliminate any node that is special - appears in database sharding (all shards are primary for their range), Kafka partition leadership (each broker is leader for some partitions), and microservices design (all service instances are stateless and replaceable). The invariant: the special node is the single point of failure. Eliminate it.","","**Where else this pattern appears:**","- **Kafka brokers:** Every broker is leader for some partitions and follower for others - all brokers are active, no broker is special.","- **Kubernetes control plane:** Multi-master Kubernetes runs multiple API servers simultaneously - all active, with etcd providing distributed consensus.","- **DNS anycast:** Multiple DNS servers share the same IP address and answer queries simultaneously - all active, geographically distributed.")
$st020 = "Active-Active architectures solve availability but create a fundamental trade-off with consistency that most teams underestimate. If two users in different regions simultaneously modify the same data (a bank account balance, a product inventory count), active-active produces a conflict that must be resolved. The resolution options - last-write-wins, manual resolution, CRDT merge - all involve either data loss, user-facing errors, or business logic complexity. Many organisations discover this trade-off only after building active-active and encountering the first conflict in production, at which point changing the conflict resolution strategy requires a full data migration."
$think020 = Join-Lines @("**Q1.** You have active-active across 2 regions, 50K requests/sec each. Region 1 fails. Region 2 only sized for 50K, now gets 100K. What happens? How do you prevent meltdown?","","*Hint:* Think about what happens when 100K req/sec hits a region sized for 50K - does the region degrade gracefully (some requests slow) or collapse (all requests fail)? Explore over-provisioning (size each region for 75-100% of total traffic) vs load shedding (deliberately reject low-priority requests at 150% capacity).","","**Q2.** Implementing multi-master database replication for active-active. Two regions simultaneously write the same counter. How do you avoid data loss or conflicts?","","*Hint:* Think about what two concurrent writes to the same counter mean for eventual consistency - do both get applied (double-increment, wrong result), or does one win (lost update, also wrong)? Explore CAS (compare-and-swap), vector clocks, and CRDT counter types that support concurrent increment without conflicts.","","**Q3 (Design Trade-off):** You're building an active-active shopping cart. A user in the US adds item A to cart. 500ms later (before replication), the same user in EU adds item B. Replication arrives - both regions have both items. But if the user removes item A on US, does EU reflect it? Design a consistency strategy for cart mutations in active-active.","","*Hint:* Think about whether a shopping cart is last-write-wins acceptable (user's most recent device wins), or whether all mutations must merge (add all items, remove items explicitly). Explore CRDT sets (add-wins, remove-wins) and whether the cart's semantics match any CRDT type.")
Upgrade-SYD "SYD-020 - Active-Active.md" $yaml020 $inv020 $evo020 $rk020 $tw020 $st020 $think020

# ============================================================
# SYD-021 - Active-Passive
# ============================================================
$yaml021 = Join-Lines @("---","id: SYD-021","title: Active-Passive","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$empty","depends_on: SYD-019, SYD-008","used_by:","related: SYD-020, SYD-019, SYD-022","tags:","  - reliability","  - intermediate","  - architecture","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 21","permalink: /syd/active-passive/","---")
$inv021 = '"One system actively serving. One system passively waiting. If active fails, promote passive. Simple, safe, proven."'
$evo021 = "Active-Passive (primary/replica) was the dominant HA pattern from the 1990s through the 2010s because it is simpler than active-active: no conflict resolution, clear write authority, familiar master-replica model. PostgreSQL streaming replication, MySQL primary-replica, and Oracle Data Guard all implement active-passive. Cloud databases (RDS, Cloud SQL) exposed active-passive as a managed failover feature. The shift to active-active began in the 2010s as latency requirements made regional proximity necessary. Active-passive remains the dominant pattern for write-heavy systems where conflict resolution complexity exceeds the benefits of dual-active writes."
$rk021 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-019 - Redundancy Failover]] - the broader pattern that active-passive implements","- [[SYD-008 - Load Balancing]] - routes traffic away from the failed primary","","**Builds On This (learn these next):**","- [[SYD-022 - Disaster Recovery]] - active-passive across regions is the basis for DR","","**Alternatives / Comparisons:**","- [[SYD-020 - Active-Active]] - more complex but better resource utilisation and no failover time","- [[SYD-022 - Disaster Recovery]] - larger-scale version of active-passive across regions")
$tw021 = Join-Lines @("**Reusable Engineering Principle:**","Simplicity enables correctness. Active-passive is correct (no conflict resolution needed) at the cost of resource utilisation (passive server is idle) and failover time (promotion takes seconds). This trade-off appears everywhere: a single database writer is simpler and more correct than multi-master; a single leader in a distributed system (Paxos, Raft) is simpler than leaderless consensus; a single on-call engineer per rotation is simpler than shared responsibility. Simplicity has a cost but often the cost is worth it.","","**Where else this pattern appears:**","- **Paxos/Raft leader election:** Distributed consensus elects one leader (active) and all other nodes are followers (passive) - conflict-free writes to the leader only.","- **Primary DNS:** A primary authoritative DNS server and secondary replicas - writes only to primary, replicas serve read traffic.","- **Git branching:** Main branch is active (production), feature branches are passive (development) - only main gets deployed.")
$st021 = "Active-passive creates a hidden performance assumption: the passive node must be able to accept 100% of the primary's write throughput at the moment of failover. If replication lag has caused the passive to fall behind, it must also catch up while simultaneously serving newly promoted traffic. Systems with high write throughput often discover that failover itself degrades performance for 60-90 seconds post-promotion as the new primary processes accumulated replication backlog while serving live writes. This post-failover degradation is rarely included in RTO calculations but is consistently observed in production failover events."
$think021 = Join-Lines @("**Q1.** Primary fails. Replication lag was 50 MB. How much data is lost? How do you recover it?","","*Hint:* Think about what 50 MB of replication lag means at the byte level - what was the write rate that produced 50 MB of lag? Explore whether the lag is in uncommitted transactions (recoverable with WAL replay) or committed writes that were not replicated (permanent loss).","","**Q2.** After failover, the passive is now primary. The old primary comes back online. How do you prevent it from accepting writes and corrupting data?","","*Hint:* Think about what happens when the old primary comes back online - does it know it is no longer primary? Explore STONITH (fencing), and how PostgreSQL's recovery.conf (or standby.signal) prevents an old primary from accepting writes after being fenced.","","**Q3 (Comparison):** Your service currently has active-passive PostgreSQL (1 primary, 1 replica). You want to add a third server. Should it be another replica (read scaling) or an active-active second primary (write scaling)? What workload characteristics determine the right choice?","","*Hint:* Think about what the current bottleneck is: read throughput (solved by read replicas) vs write throughput (requires multi-master complexity). Explore whether your workload is read-heavy or write-heavy, and what the ratio of reads to writes is at peak traffic.")
Upgrade-SYD "SYD-021 - Active-Passive.md" $yaml021 $inv021 $evo021 $rk021 $tw021 $st021 $think021

# ============================================================
# SYD-022 - Disaster Recovery
# ============================================================
$yaml022 = Join-Lines @("---","id: SYD-022","title: Disaster Recovery","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-018, SYD-019","used_by: SYD-023, SYD-024","related: SYD-018, SYD-023","tags:","  - reliability","  - advanced","  - distributed","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 22","permalink: /syd/disaster-recovery/","---")
$inv022 = '"Plan for disaster before it happens. Define recovery targets (RTO/RPO). Build infrastructure to meet them. Test regularly."'
$evo022 = "Disaster recovery as a discipline originated in the 1970s when mainframe operators created hot site arrangements - alternative data centres that could assume operations if the primary site was destroyed. The process was manual, slow (hours to days), and expensive. Cloud computing transformed DR: Amazon's multi-AZ deployment (2006) made automated failover within a region practical. Infrastructure as Code (Terraform, CloudFormation) made DR infrastructure reproducible and testable. Modern DR is infrastructure as test - you do not have a DR plan, you have DR infrastructure that is continuously exercised via chaos engineering."
$rk022 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-018 - RTO RPO]] - the metrics that define what disaster recovery must achieve","- [[SYD-019 - Redundancy Failover]] - smaller-scale failover that DR extends to cross-region","","**Builds On This (learn these next):**","- [[SYD-023 - Geo-Replication]] - data replication strategy for cross-region DR","- [[SYD-024 - Multi-Region Architecture]] - full multi-region design that includes DR capability","","**Alternatives / Comparisons:**","- [[SYD-018 - RTO RPO]] - the metrics that define DR targets","- [[SYD-019 - Redundancy Failover]] - single-region version of the same pattern")
$tw022 = Join-Lines @("**Reusable Engineering Principle:**","A plan that has never been tested is a hypothesis. DR procedures that have never been executed will fail when needed - not because of technical problems but because of untested assumptions, stale credentials, outdated runbooks, and operational muscle memory that only develops through practice. This principle applies to on-call runbooks (run in simulation before production), incident response plans (tabletop exercises), and deployment procedures (blue-green deploys must be rehearsed).","","**Where else this pattern appears:**","- **Chaos engineering:** Netflix's Chaos Monkey deliberately kills production instances to test that redundancy works as designed - continuous DR testing.","- **Fire drills:** AWS GameDay exercises and Google DiRT (Disaster and Recovery Testing) are structured DR tests with intentional failure injection.","- **Deployment runbooks:** Runbooks that are only read during incidents will have errors; runbooks that are practiced in staging will be correct during production crises.")
$st022 = "Most disaster recovery plans fail not because the technology doesn't work but because the runbook was last updated 18 months ago and no one noticed that the database password was rotated, the S3 bucket was renamed, and the secondary DNS entry expired. In post-mortems, DR test failures are rarely technical failures - they are process failures: missing monitoring, stale credentials, manual steps with implicit knowledge held by one engineer who has since left. The technical components of DR are often the easy part; the operational components are the hard part."
$think022 = Join-Lines @("**Q1.** Your RTO = 1 hour, RPO = 5 minutes. Primary DC fails. Secondary DC takes 45 min to become operational. You're within RTO. But failover testing shows actual time is 1.5 hours. Why the gap?","","*Hint:* Think about the gap between planned RTO (60 min) and actual failover time (90 min) - what is the source of the extra 30 minutes? Explore whether the gap is in infrastructure startup time, operational coordination time (waiting for monitoring to confirm, manual approval steps), or communication time.","","**Q2.** Post-disaster investigation: backups exist, but 2 days worth are corrupted (ransomware). How far back can you reliably restore?","","*Hint:* Think about how far back your backup chain extends beyond the corrupted 2-day window. Explore the trade-off between RPO (how old is the clean backup?) and the cost of the backup retention period required to guarantee clean restore options.","","**Q3 (Design Trade-off):** You need to design DR for a system with 10 TB of data in an RDS database. RTO = 2 hours, RPO = 1 hour. Budget = $3K/month. Outline the minimum DR architecture that meets RTO and RPO, and what you would add if budget allowed.","","*Hint:* Think about the spectrum from cold standby (daily backup, long restore time, cheap) to warm standby (replica in another region, faster restore, medium cost) to hot standby (synchronous replication, instant failover, expensive). Map each tier's restore time to your 2-hour RTO and 1-hour RPO requirement.")
Upgrade-SYD "SYD-022 - Disaster Recovery.md" $yaml022 $inv022 $evo022 $rk022 $tw022 $st022 $think022

Write-Host "`nBatch 2a (SYD-016 to SYD-022) complete." -ForegroundColor Cyan
